create schema if not exists instaops;
create extension if not exists pgcrypto;

create table if not exists instaops.businesses (id uuid primary key default gen_random_uuid(), name text not null, instagram_handle text, meta_page_id text, instagram_business_account_id text, access_token_encrypted text, webhook_verify_token text, connection_status text default 'demo', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists instaops.profiles (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, email text unique not null, full_name text not null, role text not null check (role in ('owner','manager','staff')), created_at timestamptz default now());
create table if not exists instaops.team_members (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, full_name text not null, role text not null, active boolean default true, created_at timestamptz default now());
create table if not exists instaops.customers (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, full_name text not null, instagram_username text not null, phone text, address text, city text, tags text[] default '{}', total_orders int default 0, lifetime_value numeric(12,2) default 0, last_order_date date, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists instaops.suppliers (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, name text not null, contact_name text, phone text, whatsapp text, email text, lead_time_days int default 3, notes text, created_at timestamptz default now());
create table if not exists instaops.products (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, supplier_id uuid references instaops.suppliers(id) on delete set null, sku text not null, name text not null, category text, variant text, price numeric(12,2) not null, cost numeric(12,2) not null, stock int default 0, active boolean default true, created_at timestamptz default now());
create table if not exists instaops.instagram_conversations (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, customer_id uuid references instaops.customers(id) on delete set null, assigned_to uuid references instaops.team_members(id) on delete set null, instagram_thread_id text, detected_intent text, status text default 'new', unread boolean default true, tags text[] default '{}', last_message_preview text, last_message_at timestamptz default now(), created_at timestamptz default now());
create table if not exists instaops.instagram_messages (id uuid primary key default gen_random_uuid(), conversation_id uuid references instaops.instagram_conversations(id) on delete cascade, sender_type text not null, body text not null, extracted_fields jsonb default '{}'::jsonb, confidence numeric(4,2), created_at timestamptz default now());
create table if not exists instaops.orders (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, order_no text unique not null, customer_id uuid references instaops.customers(id) on delete set null, conversation_id uuid references instaops.instagram_conversations(id) on delete set null, supplier_id uuid references instaops.suppliers(id) on delete set null, responsible_person_id uuid references instaops.team_members(id) on delete set null, customer_name text not null, instagram_username text, phone text, address text, city text, delivery_fee numeric(12,2) default 0, discount numeric(12,2) default 0, total_amount numeric(12,2) default 0, payment_status text default 'unpaid', payment_method text, internal_deadline date, customer_requested_delivery_date date, order_status text default 'New', delivery_status text default 'Not Started', priority text default 'normal', notes text, source_message_id uuid references instaops.instagram_messages(id) on delete set null, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists instaops.order_items (id uuid primary key default gen_random_uuid(), order_id uuid references instaops.orders(id) on delete cascade, product_id uuid references instaops.products(id) on delete set null, product_name text not null, variant text, quantity int not null default 1, unit_price numeric(12,2) not null, unit_cost numeric(12,2) not null, created_at timestamptz default now());
create table if not exists instaops.supplier_order_batches (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, supplier_id uuid references instaops.suppliers(id) on delete set null, batch_no text unique not null, status text default 'draft', created_at timestamptz default now());
create table if not exists instaops.supplier_order_batch_items (id uuid primary key default gen_random_uuid(), batch_id uuid references instaops.supplier_order_batches(id) on delete cascade, order_id uuid references instaops.orders(id) on delete cascade, product_id uuid references instaops.products(id) on delete set null, product_name text, variant text, quantity int, required_date date, notes text);
create table if not exists instaops.shipments (id uuid primary key default gen_random_uuid(), order_id uuid references instaops.orders(id) on delete cascade, shipper_name text, tracking_no text, status text default 'pending', cod_amount numeric(12,2) default 0, delivery_notes text, deadline date, created_at timestamptz default now());
create table if not exists instaops.payments (id uuid primary key default gen_random_uuid(), order_id uuid references instaops.orders(id) on delete cascade, amount numeric(12,2) not null, method text, status text default 'paid', paid_at timestamptz, created_at timestamptz default now());
create table if not exists instaops.expenses (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, category text, amount numeric(12,2) not null, description text, spent_at date default current_date, created_at timestamptz default now());
create table if not exists instaops.crm_notes (id uuid primary key default gen_random_uuid(), customer_id uuid references instaops.customers(id) on delete cascade, note text not null, created_at timestamptz default now());
create table if not exists instaops.tasks (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, customer_id uuid references instaops.customers(id) on delete set null, order_id uuid references instaops.orders(id) on delete cascade, assigned_to uuid references instaops.team_members(id) on delete set null, title text not null, status text default 'open', due_date date, priority text default 'normal', created_at timestamptz default now());
create table if not exists instaops.automation_rules (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, name text not null, trigger text not null, condition text, action text not null, active boolean default true, created_at timestamptz default now());
create table if not exists instaops.audit_logs (id uuid primary key default gen_random_uuid(), business_id uuid references instaops.businesses(id) on delete cascade, action text not null, entity_type text, entity_id uuid, metadata jsonb default '{}'::jsonb, created_at timestamptz default now());

alter table instaops.businesses enable row level security;
alter table instaops.profiles enable row level security;
alter table instaops.team_members enable row level security;
alter table instaops.customers enable row level security;
alter table instaops.suppliers enable row level security;
alter table instaops.products enable row level security;
alter table instaops.instagram_conversations enable row level security;
alter table instaops.instagram_messages enable row level security;
alter table instaops.orders enable row level security;
alter table instaops.order_items enable row level security;
alter table instaops.supplier_order_batches enable row level security;
alter table instaops.supplier_order_batch_items enable row level security;
alter table instaops.shipments enable row level security;
alter table instaops.payments enable row level security;
alter table instaops.expenses enable row level security;
alter table instaops.crm_notes enable row level security;
alter table instaops.tasks enable row level security;
alter table instaops.automation_rules enable row level security;
alter table instaops.audit_logs enable row level security;
